"use client";

import { useEffect, useState } from "react";
import { cn } from "@/lib/cn";

export function ThemeToggle() {
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    // Light is the default; only an explicit "dark" choice enables dark mode.
    // System prefers-color-scheme is intentionally ignored.
    const dark = localStorage.getItem("theme") === "dark";
    setIsDark(dark);
    document.documentElement.classList.toggle("dark", dark);
  }, []);

  function toggle() {
    const next = !isDark;
    setIsDark(next);
    document.documentElement.classList.toggle("dark", next);
    localStorage.setItem("theme", next ? "dark" : "light");
  }

  return (
    <button
      type="button"
      onClick={toggle}
      className="flex items-center gap-1 text-heading outline-none focus:outline-none focus-visible:outline-none"
      aria-label={isDark ? "Switch to light mode" : "Switch to dark mode"}
    >
      <SunIcon className="size-[17px] w-[18px]" />
      <ToggleIcon className={cn("size-6", isDark && "rotate-180")} />
      <MoonIcon className="size-4" />
    </button>
  );
}

